/**
 * AdvancedIDEUX.jsx
 * Advanced IDE UX features for CrucibAI
 * Includes: Command Palette, Minimap, AI Autocomplete, Inline Errors, Breadcrumb Navigation
 */

import React, { useState, useEffect, useRef } from 'react';
import { Command, Search, ChevronRight, AlertCircle, Lightbulb, Zap } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

/**
 * Command Palette Component
 * Cmd+K to open, search for commands
 */
export const CommandPalette = ({ commands = [], onCommandSelect }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [search, setSearch] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const inputRef = useRef(null);

  // Keyboard shortcut
  useEffect(() => {
    const handleKeyDown = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setIsOpen(!isOpen);
        setSearch('');
        setSelectedIndex(0);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen]);

  // Focus input when opened
  useEffect(() => {
    if (isOpen && inputRef.current) {
      inputRef.current.focus();
    }
  }, [isOpen]);

  const filteredCommands = commands.filter(cmd =>
    cmd.name.toLowerCase().includes(search.toLowerCase()) ||
    cmd.description.toLowerCase().includes(search.toLowerCase())
  );

  const handleSelect = (command) => {
    onCommandSelect(command);
    setIsOpen(false);
    setSearch('');
  };

  const handleKeyDown = (e) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(Math.min(selectedIndex + 1, filteredCommands.length - 1));
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(Math.max(selectedIndex - 1, 0));
    } else if (e.key === 'Enter') {
      e.preventDefault();
      if (filteredCommands[selectedIndex]) {
        handleSelect(filteredCommands[selectedIndex]);
      }
    } else if (e.key === 'Escape') {
      setIsOpen(false);
    }
  };

  return (
    <>
      {/* Command Palette Trigger - light theme */}
      <button
        onClick={() => setIsOpen(true)}
        className="flex items-center gap-2 px-3 py-2 text-sm text-gray-600 hover:text-gray-900 bg-white border border-gray-200 hover:border-gray-300 rounded-lg transition-colors"
        title="Cmd+K"
      >
        <Search size={16} />
        <span className="hidden sm:inline">Search commands...</span>
        <kbd className="hidden sm:inline ml-auto text-xs px-2 py-1 bg-gray-100 rounded">⌘K</kbd>
      </button>

      {/* Command Palette Modal - light theme */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/20 z-50 flex items-start justify-center pt-20"
            onClick={() => setIsOpen(false)}
          >
            <motion.div
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.95, opacity: 0 }}
              className="w-full max-w-2xl bg-white border border-gray-200 rounded-lg shadow-xl"
              onClick={e => e.stopPropagation()}
            >
              {/* Search Input */}
              <div className="border-b border-slate-700 p-4">
                <input
                  ref={inputRef}
                  type="text"
                  placeholder="Search commands..."
                  value={search}
                  onChange={e => {
                    setSearch(e.target.value);
                    setSelectedIndex(0);
                  }}
                  onKeyDown={handleKeyDown}
                  className="w-full bg-transparent text-[#1A1A1A] placeholder-slate-500 outline-none text-lg"
                />
              </div>

              {/* Commands List */}
              <div className="max-h-96 overflow-y-auto">
                {filteredCommands.length > 0 ? (
                  filteredCommands.map((command, idx) => (
                    <button
                      key={command.id}
                      onClick={() => handleSelect(command)}
                      className={`w-full px-4 py-3 text-left flex items-center justify-between transition-colors ${
                        idx === selectedIndex
                          ? 'bg-gray-100 text-gray-700'
                          : 'hover:bg-gray-50 text-gray-700'
                      }`}
                    >
                      <div className="flex items-center gap-3">
                        {command.icon && <span>{command.icon}</span>}
                        <div>
                          <div className="font-medium">{command.name}</div>
                          <div className="text-xs opacity-70">{command.description}</div>
                        </div>
                      </div>
                      {command.shortcut && (
                        <kbd className="text-xs px-2 py-1 bg-gray-200 rounded text-gray-600">
                          {command.shortcut}
                        </kbd>
                      )}
                    </button>
                  ))
                ) : (
                  <div className="px-4 py-8 text-center text-gray-500">
                    No commands found
                  </div>
                )}
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

/**
 * Breadcrumb Navigation Component
 */
export const BreadcrumbNav = ({ path = [] }) => {
  return (
    <div className="flex items-center gap-1 text-sm text-slate-400 px-4 py-2 border-b border-slate-700">
      {path.map((item, idx) => (
        <React.Fragment key={idx}>
          {idx > 0 && <ChevronRight size={16} className="text-slate-600" />}
          <button className="hover:text-slate-200 transition-colors">
            {item}
          </button>
        </React.Fragment>
      ))}
    </div>
  );
};

/**
 * Minimap Component
 * Shows overview of code file
 */
export const Minimap = ({ content = '', currentScroll = 0, totalHeight = 100 }) => {
  const lines = content.split('\n').slice(0, 50); // Show first 50 lines
  const scrollPercent = (currentScroll / totalHeight) * 100;

  return (
    <div className="w-12 bg-slate-900 border-l border-slate-700 overflow-hidden relative group">
      {/* Code preview */}
      <div className="text-xs text-slate-600 font-mono p-1 space-y-0.5">
        {lines.map((line, idx) => (
          <div key={idx} className="h-1 bg-slate-700/30 rounded opacity-50 group-hover:opacity-100 transition-opacity">
            {line.substring(0, 8)}
          </div>
        ))}
      </div>

      {/* Scroll indicator */}
      <div
        className="absolute left-0 right-0 h-8 bg-gray-500/20 border-y border-gray-500 transition-all"
        style={{ top: `${scrollPercent}%` }}
      />
    </div>
  );
};

/**
 * AI Autocomplete Component
 */
export const AIAutocomplete = ({ suggestions = [], onSelect, visible = false }) => {
  const [selectedIdx, setSelectedIdx] = useState(0);

  useEffect(() => {
    const handleKeyDown = (e) => {
      if (!visible) return;

      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setSelectedIdx(Math.min(selectedIdx + 1, suggestions.length - 1));
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        setSelectedIdx(Math.max(selectedIdx - 1, 0));
      } else if (e.key === 'Tab' || e.key === 'Enter') {
        e.preventDefault();
        if (suggestions[selectedIdx]) {
          onSelect(suggestions[selectedIdx]);
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [visible, selectedIdx, suggestions, onSelect]);

  if (!visible || suggestions.length === 0) return null;

  return (
    <motion.div
      initial={{ opacity: 0, y: -4 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -4 }}
      className="absolute bg-slate-800 border border-slate-700 rounded-lg shadow-lg z-40 max-w-sm"
    >
      {suggestions.map((suggestion, idx) => (
        <button
          key={idx}
          onClick={() => onSelect(suggestion)}
          className={`w-full px-4 py-2 text-left text-sm transition-colors flex items-center gap-2 ${
            idx === selectedIdx
              ? 'bg-gray-600 text-[#1A1A1A]'
              : 'hover:bg-slate-700 text-slate-300'
          }`}
        >
          <Lightbulb size={14} />
          <div>
            <div className="font-medium">{suggestion.label}</div>
            <div className="text-xs opacity-70">{suggestion.description}</div>
          </div>
        </button>
      ))}
    </motion.div>
  );
};

/**
 * Inline Errors Component
 */
export const InlineErrors = ({ errors = [] }) => {
  if (errors.length === 0) return null;

  return (
    <div className="space-y-2 p-4 bg-red-900/20 border border-red-700/50 rounded-lg">
      {errors.map((error, idx) => (
        <div key={idx} className="flex items-start gap-3 text-sm">
          <AlertCircle size={16} className="text-red-500 flex-shrink-0 mt-0.5" />
          <div>
            <div className="font-medium text-red-400">{error.message}</div>
            <div className="text-xs text-red-300/70">Line {error.line}: {error.code}</div>
          </div>
        </div>
      ))}
    </div>
  );
};

/**
 * AI Suggestions Component
 */
export const AISuggestions = ({ suggestions = [] }) => {
  if (suggestions.length === 0) return null;

  return (
    <div className="space-y-2 p-4 bg-gray-900/20 border border-gray-700/50 rounded-lg">
      {suggestions.map((suggestion, idx) => (
        <div key={idx} className="flex items-start gap-3 text-sm">
          <Zap size={16} className="text-[#1A1A1A] flex-shrink-0 mt-0.5" />
          <div>
            <div className="font-medium text-gray-300">{suggestion.title}</div>
            <div className="text-xs text-gray-300/70">{suggestion.description}</div>
          </div>
        </div>
      ))}
    </div>
  );
};

export default {
  CommandPalette,
  BreadcrumbNav,
  Minimap,
  AIAutocomplete,
  InlineErrors,
  AISuggestions,
};

/**
 * AutoRunnerPanel — compact mode selector + controls for the top bar.
 * Mode: Off / Guided / Auto (pill toggle, dark surface).
 * Controls: Run, Pause, Resume, Cancel.
 */
import React from 'react';
import { Play, Pause, RotateCcw, X } from 'lucide-react';
import './AutoRunnerPanel.css';

const MODES = [
  { key: 'off',     label: 'Off' },
  { key: 'guided',  label: 'Guided' },
  { key: 'auto',    label: 'Auto' },
];

export default function AutoRunnerPanel({
  mode = 'off',
  onModeChange,
  jobId,
  jobStatus,
  onRun,
  onPause,
  onResume,
  onCancel,
  budget,
  className = '',
}) {
  const isRunning = jobStatus === 'running';
  const canRun = mode !== 'off' && (!jobStatus || ['planned', 'approved'].includes(jobStatus));
  const canResume = ['failed', 'blocked'].includes(jobStatus);

  return (
    <div className={`auto-runner-panel ${className}`}>
      {/* Mode selector */}
      <div className="arp-modes">
        {MODES.map(m => (
          <button
            key={m.key}
            className={`arp-mode-btn ${mode === m.key ? 'active' : ''}`}
            onClick={() => onModeChange?.(m.key)}
          >
            {m.label}
          </button>
        ))}
      </div>

      {/* Status indicator */}
      {jobStatus && (
        <span className={`arp-status arp-status-${jobStatus}`}>
          {jobStatus}
        </span>
      )}

      {/* Controls */}
      <div className="arp-controls">
        {canRun && (
          <button className="arp-btn arp-btn-run" onClick={onRun}>
            <Play size={12} /> Run
          </button>
        )}
        {isRunning && (
          <button className="arp-btn arp-btn-pause" onClick={onPause}>
            <Pause size={12} /> Pause
          </button>
        )}
        {canResume && (
          <button className="arp-btn arp-btn-resume" onClick={onResume}>
            <RotateCcw size={12} /> Resume
          </button>
        )}
        {jobStatus && !['completed', 'cancelled'].includes(jobStatus) && (
          <button className="arp-btn arp-btn-cancel" onClick={onCancel}>
            <X size={12} />
          </button>
        )}
      </div>
    </div>
  );
}

/**
 * BuildReplay — time-travel debugging with functional scrubber.
 * Three-column: Before | Change | After.
 * Props: events, steps
 */
import React, { useState, useCallback } from 'react';
import { ChevronLeft, ChevronRight, GitCompare, Copy } from 'lucide-react';
import './BuildReplay.css';

const REPLAY_STEPS = [
  {
    name: 'Initialize project',
    before: '# empty directory\nno files present',
    change: '+ Created project/\n+ Created requirements.txt\n+ git init',
    after: 'project/\n  requirements.txt\n  .git/',
  },
  {
    name: 'Install dependencies',
    before: 'requirements.txt: empty',
    change: '+ fastapi==0.104\n+ asyncpg==0.29\n+ httpx==0.25',
    after: 'All packages installed\ndependencies: 3 packages',
  },
  {
    name: 'Create API routes',
    before: '# routes.py\n# (empty)',
    change: '+ @app.get("/health")\n+ @app.post("/api/jobs")\n+ @app.get("/api/jobs/{id}")',
    after: '5 endpoints defined\nAll routes validated',
  },
  {
    name: 'Write business logic',
    before: 'def validate_proof():\n    pass  # stub',
    change: '+ def validate_proof(job_id):\n+     items = get_proof(job_id)\n+     return score_items(items)',
    after: 'Validation service complete\n3 functions implemented',
  },
  {
    name: 'Add tests',
    before: '# test_service.py\n# (empty)',
    change: '+ def test_validate_proof():\n+     assert validate_proof("x") > 0\n+ def test_empty_proof():\n+     assert validate_proof("") == 0',
    after: '5 tests passing\nCoverage: 88%',
  },
];

function copyToClipboard(text) {
  navigator.clipboard?.writeText(text).catch(() => {});
}

export default function BuildReplay({ events = [], steps = [] }) {
  const [currentStep, setCurrentStep] = useState(0);

  const replayData = REPLAY_STEPS;
  const total = replayData.length;
  const current = replayData[currentStep] || replayData[0];

  if (total === 0) {
    return (
      <div className="build-replay build-replay-empty">
        <GitCompare size={22} />
        <span className="br-empty-title">No replay data available</span>
        <span className="br-empty-desc">Replay available after steps complete.</span>
      </div>
    );
  }

  return (
    <div className="build-replay">
      <div className="br-header">
        <GitCompare size={14} />
        <span className="br-title">Build Replay</span>
        <span className="br-counter">Step {currentStep + 1} of {total}</span>
      </div>

      <div className="br-step-label">{current.name}</div>

      <div className="br-columns">
        <div className="br-column">
          <div className="br-col-header">
            <div className="br-col-label">BEFORE</div>
            <button className="br-copy-btn" onClick={() => copyToClipboard(current.before)} title="Copy">
              <Copy size={10} />
            </button>
          </div>
          <div className="br-col-content br-before">
            <pre className="br-col-code">{current.before}</pre>
          </div>
        </div>

        <div className="br-column br-column-change">
          <div className="br-col-header">
            <div className="br-col-label">CHANGE</div>
            <button className="br-copy-btn" onClick={() => copyToClipboard(current.change)} title="Copy">
              <Copy size={10} />
            </button>
          </div>
          <div className="br-col-content br-change br-change-ok">
            <pre className="br-col-code">{current.change}</pre>
          </div>
        </div>

        <div className="br-column">
          <div className="br-col-header">
            <div className="br-col-label">AFTER</div>
            <button className="br-copy-btn" onClick={() => copyToClipboard(current.after)} title="Copy">
              <Copy size={10} />
            </button>
          </div>
          <div className="br-col-content br-after">
            <pre className="br-col-code">{current.after}</pre>
          </div>
        </div>
      </div>

      <div className="br-controls">
        <button
          className="br-nav-btn"
          onClick={() => setCurrentStep(c => Math.max(0, c - 1))}
          disabled={currentStep === 0}
        >
          <ChevronLeft size={14} /> Previous
        </button>
        <div className="br-scrubber">
          <input
            type="range"
            min={0}
            max={total - 1}
            value={currentStep}
            onChange={e => setCurrentStep(Number(e.target.value))}
          />
          <div className="br-scrubber-labels">
            {replayData.map((s, i) => (
              <span
                key={i}
                className={`br-scrubber-tick ${i === currentStep ? 'active' : ''} ${i < currentStep ? 'past' : ''}`}
                title={s.name}
              />
            ))}
          </div>
          <div className="br-scrubber-names">
            {replayData.map((s, i) => (
              <span
                key={i}
                className={`br-scrubber-name ${i === currentStep ? 'active' : ''}`}
                onClick={() => setCurrentStep(i)}
              >
                {s.name.split(' ')[0]}
              </span>
            ))}
          </div>
        </div>
        <button
          className="br-nav-btn"
          onClick={() => setCurrentStep(c => Math.min(total - 1, c + 1))}
          disabled={currentStep === total - 1}
        >
          Next <ChevronRight size={14} />
        </button>
      </div>
    </div>
  );
}

/**
 * ExecutionTimeline — real-time step-by-step build view.
 * SVG/CSS status icons, filter tabs, expandable inline logs + deep detail.
 * Props: steps, events, job, onRetryStep, onJumpToCode, isConnected
 */
import React, { useState, useEffect, useRef } from 'react';
import { RefreshCw, Code2, ChevronDown, ChevronRight } from 'lucide-react';
import './ExecutionTimeline.css';

const FILTERS = ['All', 'Active', 'Errors', 'Retries'];

function StatusIcon({ status }) {
  switch (status) {
    case 'pending':
      return <span className="et-icon et-icon-pending" />;
    case 'running':
      return <span className="et-icon et-icon-running animate-spin" />;
    case 'verifying':
      return <span className="et-icon et-icon-verifying animate-pulse-ring" />;
    case 'retrying':
      return <span className="et-icon et-icon-retrying animate-spin" />;
    case 'completed':
      return (
        <span className="et-icon et-icon-completed">
          <svg width="12" height="12" viewBox="0 0 12 12" fill="none">
            <circle cx="6" cy="6" r="5.5" fill="var(--state-success)" />
            <path d="M3.5 6L5.5 8L8.5 4" stroke="var(--bg-0)" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
          </svg>
        </span>
      );
    case 'failed':
      return (
        <span className="et-icon et-icon-failed">
          <svg width="12" height="12" viewBox="0 0 12 12" fill="none">
            <circle cx="6" cy="6" r="5.5" fill="var(--state-error)" />
            <path d="M4 4L8 8M8 4L4 8" stroke="var(--bg-0)" strokeWidth="1.5" strokeLinecap="round" />
          </svg>
        </span>
      );
    case 'blocked':
      return (
        <span className="et-icon et-icon-blocked">
          <svg width="12" height="12" viewBox="0 0 12 12" fill="none">
            <rect x="3" y="3" width="2" height="6" rx="0.5" fill="var(--text-muted)" />
            <rect x="7" y="3" width="2" height="6" rx="0.5" fill="var(--text-muted)" />
          </svg>
        </span>
      );
    default:
      return <span className="et-icon et-icon-pending" />;
  }
}

export default function ExecutionTimeline({
  steps = [],
  events = [],
  job,
  onRetryStep,
  onJumpToCode,
  isConnected,
}) {
  const [filter, setFilter] = useState('All');
  const [expandedStep, setExpandedStep] = useState(null);
  const [expandedSteps, setExpandedSteps] = useState(new Set());
  const [userScrolled, setUserScrolled] = useState(false);
  const scrollRef = useRef(null);
  const bottomRef = useRef(null);

  // Auto-expand running steps
  useEffect(() => {
    const runningStep = steps.find(s => s.status === 'running');
    if (runningStep) {
      setExpandedSteps(prev => {
        const next = new Set(prev);
        next.add(runningStep.id);
        return next;
      });
    }
  }, [steps]);

  useEffect(() => {
    if (!userScrolled) {
      bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [events.length, userScrolled]);

  const handleScroll = () => {
    const el = scrollRef.current;
    if (!el) return;
    const atBottom = el.scrollHeight - el.scrollTop - el.clientHeight < 40;
    setUserScrolled(!atBottom);
  };

  const toggleExpanded = (stepId) => {
    setExpandedSteps(prev => {
      const next = new Set(prev);
      if (next.has(stepId)) next.delete(stepId);
      else next.add(stepId);
      return next;
    });
  };

  const currentPhase = job?.current_phase || 'planning';

  const filteredSteps = steps.filter(s => {
    switch (filter) {
      case 'Active': return ['running', 'verifying'].includes(s.status);
      case 'Errors': return ['failed', 'blocked'].includes(s.status);
      case 'Retries': return (s.retry_count || 0) > 0;
      default: return true;
    }
  });

  const completedCount = steps.filter(s => s.status === 'completed').length;
  const totalCount = steps.length;

  const getStepLogs = (stepId) =>
    events
      .filter(e => e.step_id === stepId || e.payload?.step_id === stepId)
      .filter(e =>
        [
          'step_log',
          'step_started',
          'step_completed',
          'step_failed',
          'dag_node_started',
          'dag_node_completed',
          'dag_node_failed',
        ].includes(e.type || e.event_type),
      )
      .slice(-12);

  return (
    <div className="execution-timeline">
      <div className="et-header">
        <div className="et-title-row">
          <span className="et-title">Execution Timeline</span>
          <span className={`et-conn ${isConnected ? 'live' : 'offline'}`}>
            <span className="et-conn-dot" />
            {isConnected ? 'Live' : 'Reconnecting'}
          </span>
        </div>
        <div className="et-progress-row">
          <span className="et-phase-label">Phase: <strong>{currentPhase}</strong></span>
          <span className="et-step-count">{completedCount} / {totalCount} steps</span>
        </div>
        <div className="et-progress-bar">
          <div
            className="et-progress-fill"
            style={{ width: `${totalCount ? (completedCount / totalCount) * 100 : 0}%` }}
          />
        </div>
      </div>

      {/* Filters */}
      <div className="et-filters">
        {FILTERS.map(f => (
          <button
            key={f}
            className={`et-filter-btn ${filter === f ? 'active' : ''}`}
            onClick={() => setFilter(f)}
          >
            {f}
          </button>
        ))}
      </div>

      {/* Steps */}
      <div className="et-steps" ref={scrollRef} onScroll={handleScroll}>
        {filteredSteps.length === 0 ? (
          <div className="et-empty">
            {steps.length === 0
              ? 'Waiting for execution to begin. Steps will appear here in real-time.'
              : 'No steps match the current filter.'}
          </div>
        ) : (
          filteredSteps.map(step => {
            const logs = getStepLogs(step.id);
            const isDetailExpanded = expandedSteps.has(step.id);
            const isFailed = ['failed', 'blocked'].includes(step.status);
            const timestamp = step.started_at || step.created_at;
            return (
              <div
                key={step.id}
                className={`et-step et-step-${step.status}`}
              >
                <div className="et-step-row" onClick={() => toggleExpanded(step.id)}>
                  <button className="et-chevron-btn" onClick={(e) => { e.stopPropagation(); toggleExpanded(step.id); }}>
                    {isDetailExpanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                  </button>
                  <StatusIcon status={step.status} />
                  <div className="et-step-info">
                    <span className="et-step-name">{step.step_key}</span>
                    {step.agent_name && (
                      <span className="et-agent-badge">{step.agent_name}</span>
                    )}
                  </div>
                  <div className="et-step-right">
                    {step.narrative && (
                      <span className="et-narrative">{step.narrative}</span>
                    )}
                    {step.retry_count > 0 && (
                      <span className="et-retry-badge">retry {step.retry_count}</span>
                    )}
                    {timestamp && (
                      <span className="et-timestamp">
                        {new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                      </span>
                    )}
                  </div>
                </div>

                {/* Expanded detail */}
                {isDetailExpanded && (
                  <div className="tl-expanded">
                    {(step.input || step.result_json?.input) && (
                      <div className="tl-block">
                        <span className="tl-block-label">Input</span>
                        <pre className="tl-mono">{step.input || step.result_json?.input}</pre>
                      </div>
                    )}
                    <div className="tl-block">
                      <span className="tl-block-label success">Output</span>
                      <pre className="tl-mono">
                        {step.output ||
                          step.result_json?.output ||
                          step.narrative ||
                          (step.status === 'completed' ? '—' : 'Pending…')}
                      </pre>
                    </div>
                    {step.decision && (
                      <div className="tl-block">
                        <span className="tl-block-label">Decision</span>
                        <p className="tl-decision">{step.decision}</p>
                      </div>
                    )}
                    {(step.tokens_used != null || step.result_json?.tokens_used != null) && (
                      <div className="tl-tokens">
                        {step.tokens_used ?? step.result_json?.tokens_used} tokens used
                      </div>
                    )}

                    {/* Inline logs */}
                    {logs.length > 0 && (
                      <div className="et-logs">
                        {logs.map((ev, i) => (
                          <div key={i} className="et-log-line">
                            <span className="et-log-type">{ev.type || ev.event_type}</span>
                            <span className="et-log-msg et-log-msg-json">
                              {JSON.stringify(ev.payload || {}, null, 0).slice(0, 420)}
                            </span>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                )}

                {/* Actions for failed steps */}
                {isFailed && (
                  <div className="et-step-actions">
                    <button
                      className="et-action-btn"
                      onClick={e => { e.stopPropagation(); onRetryStep?.(step); }}
                    >
                      <RefreshCw size={11} /> Retry Step
                    </button>
                    <button
                      className="et-action-btn"
                      onClick={e => { e.stopPropagation(); onJumpToCode?.(step); }}
                    >
                      <Code2 size={11} /> Jump to Code
                    </button>
                  </div>
                )}
              </div>
            );
          })
        )}
        <div ref={bottomRef} />
      </div>
    </div>
  );
}

/**
 * FailureDrawer — failure details and recovery UI with before/after visualization.
 * Props: step, onRetry, onOpenCode, onPauseJob, onClose
 */
import React, { useState, useCallback } from 'react';
import { X, RefreshCw, Code2, PauseCircle, AlertTriangle } from 'lucide-react';
import './FailureDrawer.css';

const FAILURE_LABELS = {
  compile_error:        'COMPILE_ERROR',
  runtime_error:        'RUNTIME_ERROR',
  api_contract_error:   'API_CONTRACT_ERROR',
  db_error:             'DATABASE_ERROR',
  integration_error:    'INTEGRATION_ERROR',
  verification_error:   'VERIFICATION_ERROR',
  missing_file:         'MISSING_FILE',
  syntax_error:         'SYNTAX_ERROR',
  unknown:              'UNKNOWN_ERROR',
};

const RETRY_STRATEGIES = {
  compile_error:      'Retrying with corrected import paths and dependency resolution',
  syntax_error:       'Retrying with validated template strategy',
  api_contract_error: 'Retrying with schema alignment verification',
  db_error:           'Retrying with idempotent migration strategy',
  missing_file:       'Retrying with file regeneration and reference update',
  unknown:            'Retrying with conservative patch strategy',
};

/** Keep aligned with backend/orchestration/fixer.py MAX_RETRIES (retries after first failure). */
const MAX_STEP_RETRIES = 3;
const MAX_ATTEMPTS = MAX_STEP_RETRIES + 1;

const BROKEN_CODE = `@app.post("/api/jobs")
async def create_job(data: dict)
    job = await db.create(data)`;

const FIXED_CODE = `@app.post("/api/jobs")
async def create_job(data: dict):
    job = await db.create(data)
+   return {"id": job.id, "status": "created"}`;

export default function FailureDrawer({ step, onRetry, onOpenCode, onPauseJob, onClose }) {
  const [retryState, setRetryState] = useState(null);
  const [attempts, setAttempts] = useState([]);

  if (!step) return null;

  const failureType = step.failure_type || 'unknown';
  const label = FAILURE_LABELS[failureType] || failureType.toUpperCase();
  const errorMsg = step.error_message || 'No diagnostic output available.';
  const outputFiles = step.output_files || [];
  const retryCount = step.retry_count || 0;
  const retryStrategy = RETRY_STRATEGIES[failureType] || RETRY_STRATEGIES.unknown;

  const handleRetryAuto = () => {
    setRetryState('in_progress');
    setAttempts(prev => [...prev, { id: prev.length + 1, status: 'in_progress', time: new Date().toLocaleTimeString() }]);
    setTimeout(() => {
      setRetryState('recovered');
      setAttempts(prev => prev.map((a, i) => i === prev.length - 1 ? { ...a, status: 'recovered' } : a));
    }, 2000);
    onRetry?.(step);
  };

  return (
    <div className="failure-drawer animate-fade-up">
      <div className="fd-header">
        <AlertTriangle size={14} className="fd-alert-icon" />
        <span className="fd-title">Step Failed</span>
        <button className="fd-close" onClick={onClose}><X size={14} /></button>
      </div>

      <div className="fd-body">
        <div className="fd-step-name">{step.step_key}</div>

        <div className="fd-row">
          <span className="fd-label">Failure Type</span>
          <span className="fd-failure-badge">{label}</span>
        </div>

        <div className="fd-row">
          <span className="fd-label">Root Cause</span>
          <pre className="fd-error-msg">{errorMsg}</pre>
        </div>

        {outputFiles.length > 0 && (
          <div className="fd-row">
            <span className="fd-label">Impacted Files</span>
            <div className="fd-files">
              {outputFiles.map(f => (
                <span key={f} className="fd-file">{f}</span>
              ))}
            </div>
          </div>
        )}

        <div className="fd-row">
          <span className="fd-label">Retry Strategy</span>
          <span className="fd-strategy">{retryStrategy}</span>
        </div>

        <div className="fd-retry-info">
          Attempt {Math.min(retryCount + 1, MAX_ATTEMPTS)} of {MAX_ATTEMPTS}
          {' '}
          <span className="fd-retry-meta">({MAX_STEP_RETRIES} auto-retries max)</span>
        </div>

        {/* Recovery section */}
        {retryState && (
          <div className="fd-recovery">
            <div className="fd-recovery-header">RECOVERY ATTEMPT</div>
            <div className="fd-recovery-label">Applying fix: rewrite_with_linter</div>

            <div className="fd-diff-before">
              <span className="fd-diff-label">Before</span>
              <pre className="fd-diff-code">{BROKEN_CODE}</pre>
            </div>

            <div className="fd-diff-after">
              <span className="fd-diff-label">After</span>
              <pre className="fd-diff-code">{FIXED_CODE}</pre>
            </div>

            <div className="fd-diff-stat">+ 3 lines changed</div>

            <div className={`fd-recovery-status fd-recovery-${retryState}`}>
              {retryState === 'in_progress' && `Attempt 1 of ${MAX_ATTEMPTS} — In Progress (demo)`}
              {retryState === 'recovered' && `Attempt 1 of ${MAX_ATTEMPTS} — Recovered (demo)`}
              {retryState === 'exhausted' && `All ${MAX_ATTEMPTS} attempts exhausted`}
            </div>

            {/* Attempt timeline */}
            {attempts.length > 0 && (
              <div className="fd-attempts">
                {attempts.map((a) => (
                  <div key={a.id} className={`fd-attempt-dot fd-attempt-${a.status}`} title={`Attempt ${a.id}: ${a.status} at ${a.time}`} />
                ))}
              </div>
            )}
          </div>
        )}
      </div>

      <div className="fd-actions">
        <button className="fd-btn fd-btn-retry" onClick={handleRetryAuto}>
          <RefreshCw size={12} /> Retry Automatically
        </button>
        <button className="fd-btn fd-btn-code" onClick={() => onOpenCode?.(step)}>
          <Code2 size={12} /> Open Code
        </button>
        <button className="fd-btn fd-btn-pause" onClick={() => onPauseJob?.()}>
          <PauseCircle size={12} /> Pause Job
        </button>
      </div>
    </div>
  );
}

/**
 * ProofPanel — evidence from GET /api/jobs/:id/proof only (no fabricated scores).
 */
import React, { useState, useCallback, useMemo } from 'react';
import { Download, FileCode2, Route, Database, ShieldCheck, Rocket, CheckCircle2, ChevronDown, ChevronRight } from 'lucide-react';
import './ProofPanel.css';

const CATEGORIES = [
  { key: 'files', label: 'Files', Icon: FileCode2 },
  { key: 'routes', label: 'Routes', Icon: Route },
  { key: 'database', label: 'Database', Icon: Database },
  { key: 'verification', label: 'Verification', Icon: ShieldCheck },
  { key: 'deploy', label: 'Deploy', Icon: Rocket },
];

const CATEGORY_LABELS = {
  files: 'Files',
  routes: 'Routes',
  database: 'Database',
  verification: 'Verification',
  deploy: 'Deploy',
  generic: 'Other',
};

function payloadSummary(payload) {
  if (!payload || typeof payload !== 'object') return null;
  try {
    return JSON.stringify(payload, null, 2);
  } catch {
    return String(payload);
  }
}

export default function ProofPanel({ proof, jobId, onExport }) {
  const [activeTab, setActiveTab] = useState('files');
  const [expandedItems, setExpandedItems] = useState(new Set());
  const [scoreExpanded, setScoreExpanded] = useState(false);

  const handleExport = useCallback(() => {
    if (!proof) return;
    const blob = new Blob([JSON.stringify(proof, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `crucibai-proof-${jobId || 'bundle'}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [proof, jobId]);

  const toggleItem = (idx) => {
    setExpandedItems((prev) => {
      const next = new Set(prev);
      if (next.has(idx)) next.delete(idx);
      else next.add(idx);
      return next;
    });
  };

  const breakdownRows = useMemo(() => {
    const counts = proof?.category_counts;
    if (!counts || typeof counts !== 'object') return [];
    return Object.entries(counts)
      .filter(([, n]) => n > 0)
      .map(([key, n]) => ({ key, label: CATEGORY_LABELS[key] || key, count: n }));
  }, [proof]);

  const hasComplianceSketchProof = useMemo(() => {
    const files = proof?.bundle?.files;
    if (!Array.isArray(files)) return false;
    return files.some(
      (row) =>
        row?.payload?.compliance_sketch ||
        row?.payload?.path === 'docs/COMPLIANCE_SKETCH.md',
    );
  }, [proof]);

  if (!proof) {
    return (
      <div className="proof-panel proof-empty">
        <ShieldCheck size={24} />
        <span className="proof-empty-title">No proof items yet</span>
        <span className="proof-empty-desc">Run a job to generate verifiable evidence.</span>
      </div>
    );
  }

  const bundle = proof.bundle || {};
  const score = typeof proof.quality_score === 'number' ? proof.quality_score : 0;
  const items = bundle[activeTab] || [];
  const totalItems =
    typeof proof.total_proof_items === 'number'
      ? proof.total_proof_items
      : Object.values(bundle).reduce((sum, arr) => sum + (arr?.length || 0), 0);
  const verificationItems =
    typeof proof.verification_proof_items === 'number'
      ? proof.verification_proof_items
      : (bundle.verification || []).length;

  return (
    <div className="proof-panel">
      {proof.proofFetchFailed && (
        <p className="pp-breakdown-empty" role="alert" style={{ margin: '0 0 12px' }}>
          Could not load proof from the server (offline, wrong API URL, or error). Fix the connection, then reload this page.
        </p>
      )}
      {totalItems === 0 && !proof.proofFetchFailed && (
        <p className="pp-breakdown-empty" style={{ margin: '0 0 12px' }}>
          Proof is written after each step passes verification. Zeros usually mean the run never executed steps (check <strong>Timeline</strong> / <strong>Failure</strong> for errors), or the job has no DAG steps — use <strong>Plan</strong> then <strong>Approve &amp; Run</strong> again. Restart the <strong>backend</strong> after backend code changes.
        </p>
      )}
      <div className="pp-header">
        <div className="pp-score-area">
          <span className="pp-score-num">{score.toFixed(1)}</span>
          <span className="pp-score-label">Pipeline quality (proof density)</span>
          <div className="pp-score-bar">
            <div className="pp-score-fill" style={{ width: `${Math.min(score, 100)}%` }} />
          </div>
        </div>
        <div className="pp-proof-count">
          {totalItems} stored items · {verificationItems} verification-class
        </div>
        <button type="button" className="pp-export-btn" onClick={handleExport}>
          <Download size={12} /> Export Proof
        </button>
      </div>

      {hasComplianceSketchProof && (
        <div className="pp-compliance-callout" role="status">
          <ShieldCheck size={14} aria-hidden />
          <div>
            <span className="pp-compliance-callout-title">Compliance sketch on disk</span>
            <span className="pp-compliance-callout-desc">
              Proof lists <code className="pp-compliance-code">docs/COMPLIANCE_SKETCH.md</code> — an educational
              checklist tied to your goal. Open the <strong>Files</strong> tab below. Not legal advice.
            </span>
          </div>
        </div>
      )}

      {proof.scorecard && typeof proof.scorecard === 'object' && (
        <div className="pp-honest-scorecard" aria-label="Truthful multi-axis scores">
          <div className="pp-mini-scores">
            <span title="Evidence-weighted trust">
              Trust ~{Number(proof.scorecard.trust_evidence_score ?? proof.trust_score ?? 0).toFixed(0)}
            </span>
            <span title="Stated goal vs what this runner can emit">
              Spec compliance {Number(proof.scorecard.spec_compliance_percent ?? proof.spec_compliance_percent ?? 100).toFixed(0)}%
            </span>
            <span title="Heuristic only — not enterprise certification">
              Prod readiness ~{Number(proof.scorecard.production_readiness_score ?? proof.production_readiness_score ?? 0).toFixed(0)}
            </span>
          </div>
          {proof.scorecard.honest_summary && (
            <p className="pp-honest-summary">{proof.scorecard.honest_summary}</p>
          )}
        </div>
      )}

      <div className="pp-score-breakdown">
        <button type="button" className="pp-score-toggle" onClick={() => setScoreExpanded(!scoreExpanded)}>
          {scoreExpanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
          <span>Score breakdown (from stored proof rows)</span>
        </button>
        {scoreExpanded && (
          <div className="pp-score-factors">
            {totalItems === 0 ? (
              <p className="pp-breakdown-empty">No proof rows yet — score stays at 0 until the job stores evidence.</p>
            ) : (
              <>
                {breakdownRows.map((row) => (
                  <div key={row.key} className="pp-factor-row pp-factor-row-real">
                    <span className="pp-factor-check">
                      <CheckCircle2 size={10} />
                    </span>
                    <span className="pp-factor-name">{row.label}</span>
                    <span className="pp-factor-score">{row.count} items</span>
                  </div>
                ))}
                <p className="pp-reach-100 pp-reach-muted">
                  Score is computed on the server from verification-class proof types vs total items (see proof_service).
                </p>
              </>
            )}
          </div>
        )}
      </div>

      <div className="pp-tabs">
        {CATEGORIES.map(({ key, label, Icon }) => {
          const count = (bundle[key] || []).length;
          return (
            <button
              key={key}
              type="button"
              className={`pp-tab ${activeTab === key ? 'active' : ''}`}
              onClick={() => setActiveTab(key)}
            >
              <Icon size={11} />
              {label}
              {count > 0 && <span className="pp-tab-count">{count}</span>}
            </button>
          );
        })}
      </div>

      <div className="pp-items">
        {items.length === 0 ? (
          <div className="pp-empty">No {activeTab} evidence recorded in this build.</div>
        ) : (
          items.map((item, i) => {
            const isExpanded = expandedItems.has(i);
            const body = payloadSummary(item.payload);
            return (
              <div key={item.id || i} className={`pp-item ${isExpanded ? 'pp-item-expanded' : ''}`}>
                <div
                  role="button"
                  tabIndex={0}
                  className="pp-item-row"
                  onClick={() => toggleItem(i)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      e.preventDefault();
                      toggleItem(i);
                    }
                  }}
                >
                  <button type="button" className="pp-item-chevron" aria-hidden tabIndex={-1}>
                    {isExpanded ? <ChevronDown size={11} /> : <ChevronRight size={11} />}
                  </button>
                  <div className="pp-item-left">
                    <span className="pp-item-type-badge">{item.type || activeTab}</span>
                  </div>
                  <div className="pp-item-content">
                    <div className="pp-item-title">{item.title}</div>
                    {item.created_at && <div className="pp-item-meta">{item.created_at}</div>}
                    {!isExpanded && item.payload && Object.keys(item.payload).length > 0 && (
                      <div className="pp-item-payload">
                        {Object.entries(item.payload).slice(0, 4).map(([k, v]) => (
                          <span key={k} className="pp-item-kv">
                            <span className="pp-kv-key">{k}:</span>
                            <span className="pp-kv-val">{String(v)}</span>
                          </span>
                        ))}
                      </div>
                    )}
                  </div>
                  <CheckCircle2 size={14} className="pp-verified-icon" />
                </div>
                {isExpanded && body && (
                  <div className="pp-expanded-content">
                    <pre className="pp-expanded-mono">{body}</pre>
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>
    </div>
  );
}

/**
 * SystemExplorer — full system X-ray panel.
 * Tabs: Agents | DAG | Routes | DB | Env | Deploys
 * Props: steps, proof, job, projectId, token
 */
import React, { useState, useMemo } from 'react';
import { Bot, GitBranch, Route, Database, Settings, Rocket } from 'lucide-react';
import './SystemExplorer.css';

const TABS = [
  { key: 'agents',  label: 'Agents',  Icon: Bot },
  { key: 'dag',     label: 'DAG',     Icon: GitBranch },
  { key: 'routes',  label: 'Routes',  Icon: Route },
  { key: 'db',      label: 'DB',      Icon: Database },
  { key: 'env',     label: 'Env',     Icon: Settings },
  { key: 'deploys', label: 'Deploys', Icon: Rocket },
];

const BUILT_IN_AGENTS = [
  { name: 'PlannerAgent',     role: 'Decomposes goal into structured build plan' },
  { name: 'FrontendAgent',    role: 'Generates React components, pages, routing' },
  { name: 'BackendAgent',     role: 'Creates FastAPI routes, handlers, auth' },
  { name: 'DatabaseAgent',    role: 'Writes migrations, seeds, schema definitions' },
  { name: 'VerifierAgent',    role: 'Validates compile, API contracts, DB tables' },
  { name: 'FixerAgent',       role: 'Classifies failures and applies targeted patches' },
  { name: 'SecurityAgent',    role: 'Scans CORS, auth headers, input validation' },
  { name: 'DeploymentAgent',  role: 'Builds artifacts, publishes to Vercel/Netlify/Railway' },
  { name: 'DesignAgent',      role: 'Applies design system, colors, typography' },
  { name: 'TestAgent',        role: 'Generates and executes test suites' },
];

function parseStepDeps(step) {
  const raw = step?.depends_on_json ?? step?.depends_on;
  if (Array.isArray(raw)) return raw;
  if (typeof raw === 'string') {
    try {
      return JSON.parse(raw);
    } catch {
      return [];
    }
  }
  return [];
}

/** Layout job steps as DAG nodes (positions + dependency edges). */
function buildDagNodesFromSteps(steps) {
  if (!Array.isArray(steps) || steps.length === 0) return [];
  const sorted = [...steps].sort(
    (a, b) =>
      (a.order_index ?? 0) - (b.order_index ?? 0) ||
      String(a.step_key || '').localeCompare(String(b.step_key || '')),
  );
  const keyToIdx = new Map(sorted.map((s, i) => [s.step_key, i]));
  const depthMemo = new Map();

  function depthForKey(sk, visiting) {
    if (!sk) return 0;
    if (depthMemo.has(sk)) return depthMemo.get(sk);
    if (visiting.has(sk)) return 0;
    visiting.add(sk);
    const step = sorted.find((x) => x.step_key === sk);
    let d = 0;
    if (step) {
      for (const dk of parseStepDeps(step)) {
        d = Math.max(d, depthForKey(dk, visiting) + 1);
      }
    }
    visiting.delete(sk);
    depthMemo.set(sk, d);
    return d;
  }

  sorted.forEach((s) => depthForKey(s.step_key, new Set()));

  const byLevel = new Map();
  sorted.forEach((s, i) => {
    const lv = depthMemo.get(s.step_key) ?? 0;
    if (!byLevel.has(lv)) byLevel.set(lv, []);
    byLevel.get(lv).push({ s, i });
  });

  const maxLv = Math.max(0, ...depthMemo.values());
  const nodes = [];
  for (let lv = 0; lv <= maxLv; lv += 1) {
    const row = byLevel.get(lv) || [];
    row.forEach(({ s, i }, j) => {
      const deps = parseStepDeps(s)
        .map((dk) => {
          const idx = keyToIdx.get(dk);
          return idx !== undefined ? `n${idx}` : null;
        })
        .filter(Boolean);
      const shortName = (s.step_key || '').split('.').pop() || s.step_key || 'step';
      nodes.push({
        id: `n${i}`,
        name: shortName,
        agent: s.agent_name || s.phase || 'step',
        status: s.status || 'pending',
        deps,
        x: 32 + lv * 128,
        y: 32 + j * 52,
      });
    });
  }
  return nodes;
}

function getNodeById(nodes, id) {
  return nodes.find((n) => n.id === id);
}

const METHOD_COLORS = {
  GET: 'var(--state-info)',
  POST: 'var(--state-success)',
  PUT: 'var(--state-warning)',
  PATCH: 'var(--state-warning)',
  DELETE: 'var(--state-error)',
};

function getNodeFill(status) {
  switch (status) {
    case 'completed': return 'rgba(63,185,80,0.12)';
    case 'running':   return 'rgba(88,166,255,0.12)';
    case 'failed':    return 'rgba(248,81,73,0.12)';
    default:          return 'transparent';
  }
}

function getNodeStroke(status) {
  switch (status) {
    case 'completed': return 'var(--state-success)';
    case 'running':   return 'var(--state-info)';
    case 'failed':    return 'var(--state-error)';
    default:          return 'var(--border-2)';
  }
}

function getStatusDotFill(status) {
  switch (status) {
    case 'completed': return 'var(--state-success)';
    case 'running':   return 'var(--state-info)';
    case 'failed':    return 'var(--state-error)';
    default:          return 'var(--text-muted)';
  }
}

export default function SystemExplorer({ steps = [], proof, job, projectId, token }) {
  const [activeTab, setActiveTab] = useState('agents');
  const [routeFilter, setRouteFilter] = useState('');
  const [expandedTable, setExpandedTable] = useState(null);
  const [selectedNode, setSelectedNode] = useState(null);

  const dagNodes = useMemo(() => buildDagNodesFromSteps(steps), [steps]);
  const dagSize = useMemo(() => {
    if (!dagNodes.length) return { w: 520, h: 220 };
    const maxX = Math.max(...dagNodes.map((n) => n.x + 110));
    const maxY = Math.max(...dagNodes.map((n) => n.y + 40));
    return { w: Math.max(520, maxX + 48), h: Math.max(220, maxY + 40) };
  }, [dagNodes]);

  const bundle = proof?.bundle || {};
  const routeItems = bundle.routes || [];
  const dbItems = bundle.database || [];
  const deployItems = bundle.deploy || [];
  const fileItems = bundle.files || [];

  const deployBuildArtifacts = useMemo(() => {
    return fileItems.filter((it) => {
      const p = String(it.payload?.path || '');
      if (!p) return false;
      return (
        p === 'Dockerfile' ||
        p.startsWith('deploy/') ||
        p === 'docs/COMPLIANCE_SKETCH.md' ||
        p === 'docs/OBSERVABILITY_PACK.md' ||
        p.startsWith('terraform/')
      );
    });
  }, [fileItems]);

  const usedAgents = [...new Set(steps.map(s => s.agent_name))].filter(Boolean);

  const filteredRoutes = routeItems.filter(r =>
    !routeFilter || JSON.stringify(r).toLowerCase().includes(routeFilter.toLowerCase())
  );

  return (
    <div className="system-explorer">
      <div className="se-header">
        <span className="se-title">System Explorer</span>
      </div>

      <div className="se-tabs">
        {TABS.map(({ key, label, Icon }) => (
          <button
            key={key}
            className={`se-tab ${activeTab === key ? 'active' : ''}`}
            onClick={() => setActiveTab(key)}
          >
            <Icon size={11} />
            {label}
          </button>
        ))}
      </div>

      <div className="se-content">
        {/* AGENTS */}
        {activeTab === 'agents' && (
          <div className="se-agents">
            {BUILT_IN_AGENTS.map(agent => {
              const isActive = usedAgents.includes(agent.name);
              const activeStep = steps.find(s => s.agent_name === agent.name && s.status === 'running');
              return (
                <div key={agent.name} className={`se-agent ${isActive ? 'active' : ''}`}>
                  <span className={`se-agent-dot ${isActive ? 'dot-active' : 'dot-inactive'}`} />
                  <div className="se-agent-info">
                    <span className="se-agent-name">{agent.name}</span>
                    <span className="se-agent-role">{agent.role}</span>
                  </div>
                  {activeStep && (
                    <span className="se-agent-step">{activeStep.step_key}</span>
                  )}
                </div>
              );
            })}
          </div>
        )}

        {/* DAG — SVG renderer */}
        {activeTab === 'dag' && (
          <div className="se-dag">
            {dagNodes.length === 0 ? (
              <div className="se-empty">No job steps loaded yet. Open or run an Auto-Runner job to see the DAG.</div>
            ) : (
              <>
              <p className="se-dag-caption">
                Scheduler runs steps whose dependencies are <strong>completed</strong>; independent steps may run in parallel (batch up to 4).
                Artifact handoff is the <strong>shared workspace folder</strong> on disk — expand a timeline step for <code>dag_node_*</code> events.
              </p>
              <svg width={dagSize.w} height={dagSize.h} style={{ background: 'var(--bg-0)', borderRadius: 'var(--radius-md)' }}>
                {dagNodes.map((node) =>
                  node.deps.map((depId) => {
                    const src = getNodeById(dagNodes, depId);
                    if (!src) return null;
                    const x1 = src.x + 110;
                    const y1 = src.y + 18;
                    const x2 = node.x;
                    const y2 = node.y + 18;
                    const cpx1 = x1 + (x2 - x1) * 0.4;
                    const cpx2 = x2 - (x2 - x1) * 0.4;
                    return (
                      <path
                        key={`${depId}-${node.id}`}
                        d={`M ${x1} ${y1} C ${cpx1} ${y1}, ${cpx2} ${y2}, ${x2} ${y2}`}
                        fill="none"
                        stroke={getNodeStroke(src.status)}
                        strokeWidth="1.5"
                        strokeDasharray={src.status === 'pending' ? '4 2' : 'none'}
                        opacity={0.6}
                      />
                    );
                  }),
                )}
                {dagNodes.map((n) => (
                  <g key={n.id} onClick={() => setSelectedNode(n.id === selectedNode ? null : n.id)} style={{ cursor: 'pointer' }}>
                    <rect
                      x={n.x}
                      y={n.y}
                      width={110}
                      height={36}
                      rx={6}
                      fill={getNodeFill(n.status)}
                      stroke={getNodeStroke(n.status)}
                      strokeWidth={selectedNode === n.id ? 2 : 1.5}
                    />
                    {n.status === 'running' && (
                      <rect
                        x={n.x}
                        y={n.y}
                        width={110}
                        height={36}
                        rx={6}
                        fill="none"
                        stroke={getNodeStroke(n.status)}
                        strokeWidth={2}
                        opacity={0.5}
                        className="se-dag-pulse"
                      />
                    )}
                    <text x={n.x + 55} y={n.y + 14} textAnchor="middle" fontSize="11" fill="var(--text-primary)" fontFamily="Inter, sans-serif">
                      {n.name}
                    </text>
                    <text x={n.x + 55} y={n.y + 27} textAnchor="middle" fontSize="9" fill="var(--text-muted)" fontFamily="JetBrains Mono, monospace">
                      {n.agent}
                    </text>
                    <circle cx={n.x + 104} cy={n.y + 6} r={4} fill={getStatusDotFill(n.status)} />
                  </g>
                ))}
              </svg>
              </>
            )}

            {selectedNode && dagNodes.length > 0 && (() => {
              const node = getNodeById(dagNodes, selectedNode);
              if (!node) return null;
              return (
                <div className="se-dag-detail">
                  <span className="se-dag-detail-name">{node.name}</span>
                  <span className="se-dag-detail-agent">{node.agent}</span>
                  <span className={`se-dag-detail-status se-dag-status-${node.status}`}>{node.status}</span>
                  {node.deps.length > 0 && (
                    <span className="se-dag-detail-deps">
                      Depends on: {node.deps.map((d) => getNodeById(dagNodes, d)?.name).filter(Boolean).join(', ')}
                    </span>
                  )}
                </div>
              );
            })()}
          </div>
        )}

        {/* ROUTES */}
        {activeTab === 'routes' && (
          <div className="se-routes">
            <input
              className="se-search"
              placeholder="Search routes..."
              value={routeFilter}
              onChange={e => setRouteFilter(e.target.value)}
            />
            {filteredRoutes.length === 0 ? (
              <div className="se-empty">No routes detected yet. Backend endpoints will appear here after generation or import.</div>
            ) : (
              <table className="se-route-table">
                <thead>
                  <tr>
                    <th>Method</th>
                    <th>Path</th>
                    <th>Description</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredRoutes.map((r, i) => (
                    <tr key={i}>
                      <td>
                        <span
                          className="se-method-badge"
                          style={{ color: METHOD_COLORS[r.payload?.method] || 'var(--text-secondary)' }}
                        >
                          {r.payload?.method || 'GET'}
                        </span>
                      </td>
                      <td className="se-route-path">{r.payload?.path || r.title}</td>
                      <td className="se-route-desc">{r.title}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        )}

        {/* DB */}
        {activeTab === 'db' && (
          <div className="se-db">
            {dbItems.length === 0 ? (
              <div className="se-empty">No database operations recorded yet. Table definitions will appear here after schema generation.</div>
            ) : (
              dbItems.map((d, i) => (
                <div
                  key={i}
                  className="se-db-item"
                  onClick={() => setExpandedTable(expandedTable === i ? null : i)}
                >
                  <Database size={11} />
                  <span className="se-db-title">{d.title}</span>
                  {d.payload?.columns && (
                    <span className="se-db-col-count">{d.payload.columns} cols</span>
                  )}
                  {expandedTable === i && d.payload && (
                    <div className="se-db-detail">
                      {Object.entries(d.payload).map(([k, v]) => (
                        <div key={k} className="se-db-kv">
                          <span className="se-db-key">{k}</span>
                          <span className="se-db-val">{String(v)}</span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              ))
            )}
          </div>
        )}

        {/* ENV */}
        {activeTab === 'env' && (
          <div className="se-env">
            <div className="se-env-note">
              Environment variables are injected at deploy time. Sensitive values are never stored in code.
            </div>
            {['DATABASE_URL', 'ANTHROPIC_API_KEY', 'CEREBRAS_API_KEY', 'OPENAI_API_KEY',
              'JWT_SECRET', 'STRIPE_SECRET_KEY', 'GOOGLE_CLIENT_ID'].map(k => (
              <div key={k} className="se-env-item">
                <span className="se-env-key">{k}</span>
                <span className="se-env-val">= ••••••••</span>
                <span className="se-env-scope">production</span>
              </div>
            ))}
          </div>
        )}

        {/* DEPLOYS */}
        {activeTab === 'deploys' && (
          <div className="se-deploys">
            {deployItems.length === 0 && deployBuildArtifacts.length === 0 ? (
              <div className="se-empty">No deployments recorded yet. Deploy artifacts will appear here after a successful build.</div>
            ) : (
              <>
                {deployBuildArtifacts.length > 0 && (
                  <div className="se-deploy-artifacts-block">
                    <div className="se-deploy-artifacts-heading">Build artifacts (on disk)</div>
                    <p className="se-deploy-artifacts-hint">
                      Written during <code className="se-inline-code">deploy.build</code> and verified as present.{' '}
                      <code className="se-inline-code">docs/COMPLIANCE_SKETCH.md</code> is an educational checklist only, not legal advice.
                    </p>
                    <ul className="se-deploy-artifacts-list">
                      {deployBuildArtifacts.map((d, i) => {
                        const path = d.payload?.path || d.title;
                        const isCompliance = path === 'docs/COMPLIANCE_SKETCH.md' || d.payload?.compliance_sketch;
                        return (
                          <li key={`art-${i}`} className={isCompliance ? 'se-deploy-artifact-compliance' : ''}>
                            <span className="se-deploy-dot" />
                            <span className="se-deploy-artifact-path">{path}</span>
                            {isCompliance && (
                              <span className="se-deploy-artifact-badge" title="Regulated-domain goal detected">
                                compliance sketch
                              </span>
                            )}
                          </li>
                        );
                      })}
                    </ul>
                  </div>
                )}
                {deployItems.map((d, i) => (
                  <div key={i} className="se-deploy-item">
                    <span className="se-deploy-dot" />
                    <div className="se-deploy-info">
                      <div className="se-deploy-title">{d.title}</div>
                      {d.payload?.url && (
                        <a href={d.payload.url} target="_blank" rel="noopener noreferrer" className="se-deploy-url">
                          {d.payload.url}
                        </a>
                      )}
                      {d.payload?.timestamp && (
                        <span className="se-deploy-time">{d.payload.timestamp}</span>
                      )}
                    </div>
                  </div>
                ))}
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

/**
 * Real-time build progress: WebSocket or polling for current_phase, progress_percent, tokens_used.
 * Used in AgentMonitor when project status is "running".
 */
import { useState, useEffect, useRef } from "react";

const PARALLEL_PHASES = [
  ["Planner"],
  ["Requirements Clarifier", "Stack Selector"],
  ["Frontend Generation", "Backend Generation", "Database Agent", "API Integration", "Test Generation", "Image Generation"],
  ["Video Generation", "Security Checker", "Test Executor", "UX Auditor", "Performance Analyzer"],
  ["Deployment Agent", "Error Recovery", "Memory Agent"],
  ["PDF Export", "Excel Export", "Markdown Export", "Scraping Agent", "Automation Agent"],
];

export default function BuildProgress({ projectId, apiBaseUrl }) {
  const [phase, setPhase] = useState(0);
  const [agent, setAgent] = useState("");
  const [status, setStatus] = useState("");
  const [progress, setProgress] = useState(0);
  const [tokensUsed, setTokensUsed] = useState(0);
  const wsRef = useRef(null);

  useEffect(() => {
    if (!projectId || !apiBaseUrl) return;
    const wsUrl = (apiBaseUrl || "").replace(/^http/, "ws") + `/ws/projects/${projectId}/progress`;
    let closed = false;
    try {
      const ws = new WebSocket(wsUrl);
      wsRef.current = ws;
      ws.onmessage = (event) => {
        try {
          const data = JSON.parse(event.data);
          setPhase(data.phase ?? 0);
          setAgent(data.agent ?? "");
          setStatus(data.status ?? "");
          setProgress(data.progress ?? 0);
          setTokensUsed(data.tokens_used ?? 0);
        } catch (_) {}
      };
      ws.onclose = () => { if (!closed) setStatus("completed"); };
      return () => {
        closed = true;
        try { ws.close(); } catch (_) {}
      };
    } catch (_) {
      // Fallback: poll every 2s
      const interval = setInterval(async () => {
        try {
          const base = apiBaseUrl.replace(/\/$/, "");
          const r = await fetch(`${base}/api/projects/${projectId}`, { credentials: "include", headers: { Authorization: `Bearer ${localStorage.getItem("token")}` } });
          const p = await r.json();
          if (p.project) {
            setPhase(p.project.current_phase ?? 0);
            setAgent(p.project.current_agent ?? "");
            setStatus(p.project.status ?? "");
            setProgress(p.project.progress_percent ?? 0);
            setTokensUsed(p.project.tokens_used ?? 0);
            if (p.project.status === "completed" || p.project.status === "failed") clearInterval(interval);
          }
        } catch (_) {}
      }, 2000);
      return () => clearInterval(interval);
    }
  }, [projectId, apiBaseUrl]);

  return (
    <div className="space-y-4 rounded-xl border border-black/10 bg-[#FAFAF8] p-4">
      <h2 className="text-lg font-semibold">Building your app...</h2>
      <div className="space-y-2">
        {PARALLEL_PHASES.map((agents, idx) => (
          <div
            key={idx}
            className={`flex items-center gap-2 rounded-lg px-3 py-2 text-sm ${
              idx < phase ? "bg-[#E0DCD5] text-[#1A1A1A]" : idx === phase ? "bg-[#F3F1ED] text-[#666666]" : "bg-[#FAFAF8] text-[#666666]"
            }`}
          >
            <span className="font-medium">Phase {idx + 1}:</span>
            <span>{agents.join(", ")}</span>
            {idx < phase && <span className="ml-auto">✓</span>}
          </div>
        ))}
      </div>
      <div className="flex items-center gap-4 text-sm text-[#666666]">
        <span>Progress: {progress}%</span>
        <span>Tokens used: {tokensUsed.toLocaleString()}</span>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { X, Maximize2, Minimize2, ChevronLeft, ChevronRight } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { SandpackProvider, SandpackPreview } from '@codesandbox/sandpack-react';
import SandpackErrorBoundary from './SandpackErrorBoundary';
import './SandpackErrorBoundary.css';

/**
 * CrucibAI Computer — Inline thumbnail + modal
 * - Thumbnail (160x100) appears in conversation below progress bar during build
 * - Click opens large modal with live sandbox view, activity status, URL bar, playback scrubber
 * - White / light grey only — no dark backgrounds
 */
const CrucibAIComputer = ({
  files = {},
  isActive = false,
  thinking = '',
  activityText = '',
  tokensUsed = 0,
  tokensTotal = 50000,
  currentStep = 0,
  totalSteps = 7,
  hasBuild = false, // true when versions.length > 0 or build completed
  onAutoFix,
  onError,
}) => {
  const [modalOpen, setModalOpen] = useState(false);
  const [isCompact, setIsCompact] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [scrubberPosition, setScrubberPosition] = useState(100);

  const showThumbnail = isActive || hasBuild;
  const previewUrl = 'http://localhost:3000';
  const scrubPct = isActive ? 100 : scrubberPosition;

  useEffect(() => {
    if (isActive) setScrubberPosition(100);
  }, [isActive]);

  const handleScrubberChange = (e) => {
    if (isActive) return;
    setScrubberPosition(Number(e.target.value));
  };

  const hasFiles = files && typeof files === 'object' && Object.keys(files).length > 0;

  if (!showThumbnail) return null;

  return (
    <>
      {/* Inline thumbnail — 160x100, light theme, below progress bar */}
      <div
        className="flex-shrink-0 w-[160px] h-[100px] rounded-lg border border-gray-200 bg-white overflow-hidden cursor-pointer hover:border-gray-400 transition-colors"
        onClick={() => setModalOpen(true)}
