  const config = statusConfig[status] || statusConfig.idle;
  const Icon = config.icon;

  if (status === 'idle') return null;

  return (
    <motion.div
      initial={{ opacity: 0, y: -10 }}
      animate={{ opacity: 1, y: 0 }}
      className={`p-4 rounded-lg border border-gray-700 ${config.bg}`}
