              type="text"
              placeholder="Search features..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="search-input"
            />
          </div>
        )}

        <nav className="sidebar-nav">
          {Object.entries(filteredFeatures).map(([sectionKey, section]) => {
            const SectionIcon = section.icon;
            const isExpanded = expandedSections[sectionKey];
            
            return (
              <div key={sectionKey} className="nav-section">
                <button
                  className="section-header"
                  onClick={() => toggleSection(sectionKey)}
                >
                  <SectionIcon size={18} className="section-icon" />
                  {sidebarOpen && (
                    <>
                      <span className="section-label">{section.label}</span>
                      <ChevronRight 
                        size={16} 
                        className={`section-toggle ${isExpanded ? 'expanded' : ''}`}
                      />
                    </>
                  )}
                </button>

                {isExpanded && (
                  <div className="section-items">
                    {section.items.map(item => {
                      const ItemIcon = item.icon;
                      return (
                        <button
                          key={item.id}
                          className={`nav-item ${currentPage === item.id ? 'active' : ''}`}
                          title={`${item.label} - ${item.description}`}
                        >
                          <ItemIcon size={18} className="nav-icon" />
                          {sidebarOpen && (
                            <div className="nav-item-content">
                              <span className="nav-label">{item.label}</span>
                              <span className="nav-description">{item.description}</span>
                            </div>
                          )}
                        </button>
                      );
                    })}
                  </div>
                )}
              </div>
            );
          })}
        </nav>

        <div className="sidebar-footer">
          {sidebarOpen && (
            <>
              <div className="user-info">
                <div className="user-avatar">U</div>
                <div className="user-details">
                  <div className="user-name">User</div>
                  <div className="user-status">Free Plan</div>
                </div>
              </div>
              <div className="footer-actions">
                <button className="footer-btn" title="Profile">
                  <User size={16} />
                  Profile
                </button>
                <button className="footer-btn" title="Logout">
                  <LogOut size={16} />
                  Logout
                </button>
              </div>
            </>
          )}
        </div>
      </aside>

      {/* Main Content */}
      <div className="main-content-pro">
        {/* Preview Panel */}
        <div className="preview-panel" style={{ width: `${dividerPos}%` }}>
          <div className="preview-header">
            <h2>Preview</h2>
            <div className="preview-controls">
              <button className="preview-btn" title="Refresh">🔄</button>
              <button className="preview-btn" title="Fullscreen">⛶</button>
              <button className="preview-btn" title="Settings">⚙️</button>
            </div>
          </div>
          <div className="preview-content">
            {previewContent || (
              <div className="preview-placeholder">
                <div className="placeholder-icon">👁️</div>
                <p>Preview will appear here</p>
                <small>Your app preview renders in real-time</small>
              </div>
            )}
          </div>
        </div>

        {/* Resizable Divider */}
        <div 
          className="divider-pro"
          onMouseDown={() => setIsDragging(true)}
          title="Drag to resize"
        >
          <div className="divider-handle">⋮⋮</div>
        </div>

        {/* Input Panel */}
        <div className="input-panel" style={{ width: `${100 - dividerPos}%` }}>
          <div className="input-header">
            <h2>Build</h2>
            <div className="input-header-actions">
              <button className="header-btn" title="Notifications">
                <Bell size={18} />
              </button>
              <button className="header-btn" title="Help">
                <HelpCircle size={18} />
              </button>
            </div>
          </div>

          {/* Chat Messages */}
          <div className="chat-messages">
            {chatMessages && chatMessages.length > 0 ? (
              chatMessages.map((msg, idx) => (
                <div key={idx} className={`message message-${msg.role}`}>
                  <div className="message-content">{msg.content}</div>
                </div>
              ))
            ) : (
              <div className="empty-state">
                <div className="empty-icon">💬</div>
                <p>Start building your app</p>
                <small>Describe what you want to create</small>
              </div>
            )}
            {isLoading && (
              <div className="message message-system">
                <div className="loading-spinner">
                  <span className="spinner"></span>
                  Processing...
                </div>
              </div>
            )}
          </div>

          {/* Input Area */}
          <div className="input-area">
            <div className="input-wrapper">
              <input
                type="text"
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
                placeholder="Describe what you want to build..."
                className="input-field"
                disabled={isLoading}
              />
              <button
                onClick={handleSendMessage}
                disabled={isLoading || !inputValue.trim()}
                className="send-button"
                title="Send"
              >
                {isLoading ? '⏳' : '→'}
              </button>
            </div>
            <div className="input-hint">
              ✨ Tip: Be specific about features, design, and functionality
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default WorkspaceLayoutPro;

import React, { useState, useRef, useEffect } from 'react';
import { 
  Menu, X, Settings, Home, Zap, BarChart3, HelpCircle, Search, Bell, LogOut, User,
  ChevronRight, Lightbulb, BookOpen, Download, Eye, Share2, Smartphone
} from 'lucide-react';
import './WorkspaceLayoutSimple.css';

/**
 * Simplified Workspace Layout - For Non-Developers
 * Features:
 * - Large, easy-to-use preview
 * - Simple chat interface
 * - Minimal sidebar with essential features only
 * - Beginner-friendly design
 * - Clear visual feedback
 */

export const WorkspaceLayoutSimple = ({ 
  previewContent, 
  chatMessages, 
  onSendMessage, 
  isLoading,
  currentPage = 'workspace'
}) => {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [inputValue, setInputValue] = useState('');
  const containerRef = useRef(null);

  // Simplified features for non-developers
  const quickFeatures = [
    { id: 'templates', label: 'Templates', icon: BookOpen, description: 'Start from template' },
    { id: 'examples', label: 'Examples', icon: Lightbulb, description: 'See examples' },
    { id: 'share', label: 'Share', icon: Share2, description: 'Share your app' },
    { id: 'export', label: 'Export', icon: Download, description: 'Download app' },
    { id: 'help', label: 'Help', icon: HelpCircle, description: 'Get help' },
  ];

  const handleSendMessage = () => {
    if (inputValue.trim()) {
      onSendMessage?.(inputValue);
      setInputValue('');
    }
  };

  return (
    <div className="workspace-layout-simple" ref={containerRef}>
      {/* Header */}
      <header className="header-simple">
        <div className="header-left">
          <button 
            className="menu-toggle"
            onClick={() => setSidebarOpen(!sidebarOpen)}
            title={sidebarOpen ? 'Hide menu' : 'Show menu'}
          >
            {sidebarOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
          <div className="header-logo">
            <div className="logo-icon">⬜</div>
            <span className="logo-text">CrucibAI</span>
          </div>
        </div>

        <div className="header-right">
          <button className="header-icon-btn" title="Notifications">
            <Bell size={20} />
          </button>
          <button className="header-icon-btn" title="Settings">
            <Settings size={20} />
          </button>
          <div className="user-menu">
            <div className="user-avatar-small">U</div>
            <button className="header-icon-btn" title="Logout">
              <LogOut size={20} />
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <div className="main-content-simple">
        {/* Sidebar */}
        {sidebarOpen && (
          <aside className="sidebar-simple">
            <nav className="nav-simple">
              <div className="nav-section-simple">
                <h3 className="nav-title">Quick Actions</h3>
                <div className="quick-actions">
                  {quickFeatures.map(feature => {
                    const Icon = feature.icon;
                    return (
                      <button
                        key={feature.id}
                        className={`quick-action ${currentPage === feature.id ? 'active' : ''}`}
                        title={feature.description}
                      >
                        <Icon size={24} />
                        <span>{feature.label}</span>
                      </button>
                    );
                  })}
                </div>
              </div>

              <div className="nav-section-simple">
                <h3 className="nav-title">Resources</h3>
                <button className="nav-link-simple">
                  <BookOpen size={18} />
                  <span>Documentation</span>
                  <ChevronRight size={16} />
                </button>
                <button className="nav-link-simple">
                  <Lightbulb size={18} />
                  <span>Tips & Tricks</span>
                  <ChevronRight size={16} />
                </button>
                <button className="nav-link-simple">
                  <HelpCircle size={18} />
                  <span>Support</span>
                  <ChevronRight size={16} />
                </button>
              </div>
            </nav>
          </aside>
        )}

        {/* Content Area */}
        <div className="content-area-simple">
          {/* Preview Section */}
          <section className="preview-section-simple">
            <div className="section-header-simple">
              <h2>Your App Preview</h2>
              <div className="preview-actions">
                <button className="action-btn" title="Refresh">
                  🔄
                </button>
                <button className="action-btn" title="Fullscreen">
                  ⛶
                </button>
              </div>
            </div>
            <div className="preview-box-simple">
              {previewContent || (
                <div className="preview-placeholder-simple">
                  <div className="placeholder-icon-large">📱</div>
                  <h3>Your app will appear here</h3>
                  <p>Describe what you want to build in the chat below</p>
                </div>
              )}
            </div>
          </section>

          {/* Chat Section */}
          <section className="chat-section-simple">
            <div className="section-header-simple">
              <h2>Build Your App</h2>
            </div>

            {/* Messages */}
            <div className="chat-box-simple">
              {chatMessages && chatMessages.length > 0 ? (
                chatMessages.map((msg, idx) => (
                  <div key={idx} className={`chat-message-simple message-${msg.role}`}>
                    <div className="message-bubble">{msg.content}</div>
                  </div>
                ))
              ) : (
                <div className="welcome-message">
                  <h3>👋 Welcome to CrucibAI!</h3>
                  <p>Tell me what kind of app you want to build, and I'll create it for you.</p>
                  <div className="suggestion-chips">
                    <button className="chip">Todo App</button>
                    <button className="chip">Weather App</button>
                    <button className="chip">Chat App</button>
                  </div>
                </div>
              )}

              {isLoading && (
                <div className="chat-message-simple message-system">
                  <div className="loading-dots">
                    <span></span>
                    <span></span>
                    <span></span>
                  </div>
                </div>
              )}
            </div>

            {/* Input */}
            <div className="input-section-simple">
              <div className="input-wrapper-simple">
                <input
                  type="text"
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
                  placeholder="Describe your app idea..."
                  className="input-field-simple"
                  disabled={isLoading}
                />
                <button
                  onClick={handleSendMessage}
                  disabled={isLoading || !inputValue.trim()}
                  className="send-btn-simple"
                  title="Send"
                >
                  {isLoading ? '⏳' : '✈️'}
                </button>
              </div>
              <div className="input-helper">
                💡 Example: "Create a todo list app with add, delete, and mark complete features"
              </div>
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default WorkspaceLayoutSimple;

import {
  Database,
  Loader2,
  Layers,
} from 'lucide-react';
import CrucibAIComputer from '../CrucibAIComputer';
import { normalizeWorkspacePath } from './pathUtils';

/**
 * Pro-only workbench panels extracted from Workspace.jsx (A-01 modularization).
 */
export default function WorkspaceProPanels({
  activePanel,
  projectIdFromUrl,
  token,
  serverDbErr,
  serverDbLoading,
  serverDbSnapshots,
  dbPanelMerge,
  setFiles,
  setActiveFile,
  setActivePanel,
  serverDocsErr,
  serverDocsLoading,
  mergedDocFiles,
  docsSelectedPath,
  setDocsSelectedPath,
  analyticsErr,
  analyticsLoading,
  analyticsData,
  buildHistoryList,
  buildTimelineEvents,
  agentsActivity,
  agentApiStatuses,
  projectSandboxErr,
  projectSandboxLoading,
  projectSandboxLogs,
  files,
  versions,
  buildHistoryLoading,
  isBuilding,
  sandpackFiles,
  projectBuildProgress,
  currentPhase,
}) {
  return (
    <>
      {activePanel === 'database' && (
        <div className="flex-1 min-h-0 overflow-y-auto p-4">
          {serverDbErr && projectIdFromUrl && (
            <div className="text-xs mb-3 px-2 py-1.5 rounded-lg" style={{ background: 'rgba(248,113,113,0.12)', color: '#fca5a5' }}>{serverDbErr}</div>
          )}
          {projectIdFromUrl && serverDbLoading && (
            <div className="flex items-center gap-2 text-xs mb-3" style={{ color: 'var(--theme-muted)' }}>
              <Loader2 className="w-3.5 h-3.5 animate-spin" />
              Loading schema from project workspace…
            </div>
          )}
          {dbPanelMerge.hasRows ? (
            <div className="space-y-3">
              {serverDbSnapshotsSection(serverDbSnapshots, setFiles, setActiveFile, setActivePanel)}
              {dbPanelMerge.editorOnly.length > 0 && (
                <div className="rounded-xl p-4 border" style={{ background: 'var(--theme-surface2)', borderColor: 'var(--theme-border)' }}>
                  <div className="flex items-center gap-2 mb-3">
                    <div className="text-xs font-semibold uppercase tracking-wider" style={{ color: 'var(--theme-muted)' }}>In editor</div>
                    <span className="text-[10px] px-1.5 py-0.5 rounded font-medium" style={{ background: 'rgba(255,255,255,0.08)', color: 'var(--theme-muted)' }}>local</span>
                  </div>
                  <div className="space-y-2">
                    {dbPanelMerge.editorOnly.map((row) => (
                      <button
                        key={row.displayKey}
                        type="button"
                        onClick={() => { setActiveFile(row.displayKey); setActivePanel('code'); }}
                        className="w-full flex items-center gap-2.5 px-3 py-2.5 rounded-lg text-xs text-left transition hover:bg-white/5 border"
                        style={{ borderColor: 'var(--theme-border)', color: 'var(--theme-text)' }}
                      >
                        <Database className="w-3.5 h-3.5 shrink-0" style={{ color: '#a78bfa' }} />
                        <span className="truncate">{row.path}</span>
                        <span className="ml-auto shrink-0" style={{ color: 'var(--theme-muted)' }}>{row.content?.split('\n').length || 0}L</span>
                      </button>
                    ))}
                  </div>
                </div>
              )}
              {dbPanelMerge.inferredTables.length > 0 && (
                <div className="rounded-xl p-4 border" style={{ background: 'var(--theme-surface2)', borderColor: 'var(--theme-border)' }}>
                  <div className="text-xs font-semibold uppercase tracking-wider mb-3" style={{ color: 'var(--theme-muted)' }}>Tables ({dbPanelMerge.inferredTables.length})</div>
                  <div className="space-y-1.5">
                    {dbPanelMerge.inferredTables.map((t) => (
                      <div key={t} className="flex items-center gap-2.5 px-3 py-2 rounded-lg text-xs" style={{ background: 'rgba(255,255,255,0.03)', color: 'var(--theme-text)' }}>
                        <div className="w-2 h-2 rounded-sm" style={{ background: '#3b82f6' }} />
                        {t}
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center h-full gap-3 py-12" style={{ color: 'var(--theme-muted)' }}>
              <Database className="w-8 h-8 opacity-30" />
              <div className="text-center">
                <div className="text-sm font-medium mb-1">No database schema yet</div>
                <div className="text-xs opacity-70 max-w-xs">
                  {projectIdFromUrl ? 'No SQL/schema files in the saved workspace yet. Run a fullstack build or add schema under the project.' : 'Open a saved project or build a fullstack app to see schema files.'}
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activePanel === 'docs' && (
        <div className="flex flex-1 min-h-0 overflow-hidden">
          <div className="w-[38%] min-w-[140px] border-r overflow-y-auto shrink-0" style={{ borderColor: 'var(--theme-border)' }}>
            {serverDocsErr && projectIdFromUrl && (
              <div className="text-[11px] m-2 p-2 rounded-lg" style={{ background: 'rgba(248,113,113,0.12)', color: '#fca5a5' }}>{serverDocsErr}</div>
            )}
            {projectIdFromUrl && serverDocsLoading && (
              <div className="flex items-center gap-2 text-xs p-3" style={{ color: 'var(--theme-muted)' }}>
                <Loader2 className="w-3.5 h-3.5 animate-spin" />
                Loading…
              </div>
            )}
            {mergedDocFiles.length === 0 ? (
              <div className="p-4 text-xs" style={{ color: 'var(--theme-muted)' }}>No Markdown files found (.md / .mdx).</div>
            ) : (
              <div className="p-2 space-y-0.5">
                {mergedDocFiles.map((d) => {
                  const active = normalizeWorkspacePath(d.path) === normalizeWorkspacePath(docsSelectedPath);
                  return (
                    <button
                      key={`${d.source}-${d.path}`}
                      type="button"
                      onClick={() => setDocsSelectedPath(d.path)}
                      className="w-full text-left px-2.5 py-2 rounded-lg text-xs transition truncate"
                      style={{
                        background: active ? 'rgba(255,255,255,0.08)' : 'transparent',
                        color: active ? 'var(--theme-text)' : 'var(--theme-muted)',
                        border: active ? '1px solid var(--theme-border)' : '1px solid transparent',
                      }}
                    >
                      <span className="block truncate">{d.path}</span>
                      <span className="text-[10px] opacity-70">{d.source === 'server' ? 'workspace' : 'editor'}</span>
                    </button>
                  );
                })}
              </div>
            )}
          </div>
          <div className="flex-1 min-w-0 overflow-y-auto p-4">
            {mergedDocFiles.length > 0 && (() => {
              const doc = mergedDocFiles.find((d) => normalizeWorkspacePath(d.path) === normalizeWorkspacePath(docsSelectedPath)) || mergedDocFiles[0];
              return (
                <div>
                  <div className="text-xs font-semibold mb-2" style={{ color: 'var(--theme-muted)' }}>{doc.path}</div>
                  <pre className="text-xs whitespace-pre-wrap font-sans leading-relaxed" style={{ color: 'var(--theme-text)' }}>{doc.content || '—'}</pre>
                </div>
              );
            })()}
          </div>
        </div>
      )}

      {activePanel === 'analytics' && (
        <div className="flex-1 min-h-0 overflow-y-auto p-4 space-y-3">
          {!token && (
            <div className="text-sm" style={{ color: 'var(--theme-muted)' }}>Sign in to load usage and jobs.</div>
          )}
          {analyticsErr && (
            <div className="text-xs px-2 py-1.5 rounded-lg" style={{ background: 'rgba(248,113,113,0.12)', color: '#fca5a5' }}>{analyticsErr}</div>
          )}
          {token && analyticsLoading && (
            <div className="flex items-center gap-2 text-xs" style={{ color: 'var(--theme-muted)' }}>
              <Loader2 className="w-3.5 h-3.5 animate-spin" />
              Loading analytics…
            </div>
          )}
          {token && !analyticsLoading && analyticsData && (
            <>
              {projectIdFromUrl && (
                <div className="rounded-xl p-4 border" style={{ background: 'var(--theme-surface2)', borderColor: 'var(--theme-border)' }}>
                  <div className="text-xs font-semibold uppercase tracking-wider mb-2" style={{ color: 'var(--theme-muted)' }}>This project</div>
                  <div className="space-y-1 text-xs" style={{ color: 'var(--theme-text)' }}>
                    <div><span style={{ color: 'var(--theme-muted)' }}>Recorded builds</span><span className="ml-2 font-medium">{buildHistoryList.length}</span></div>
                    <div><span style={{ color: 'var(--theme-muted)' }}>Orchestration events (session)</span><span className="ml-2 font-medium">{buildTimelineEvents.length}</span></div>
                    <div>
                      <span style={{ color: 'var(--theme-muted)' }}>Tokens (ledger, this id)</span>
                      <span className="ml-2 font-medium">
                        {(analyticsData.tokens?.by_project && analyticsData.tokens.by_project[projectIdFromUrl] != null)
                          ? Number(analyticsData.tokens.by_project[projectIdFromUrl]).toLocaleString()
                          : '—'}
                      </span>
                    </div>
                  </div>
                </div>
              )}
              <div className="rounded-xl p-4 border" style={{ background: 'var(--theme-surface2)', borderColor: 'var(--theme-border)' }}>
                <div className="text-xs font-semibold uppercase tracking-wider mb-2" style={{ color: 'var(--theme-muted)' }}>Account usage</div>
                <div className="text-2xl font-bold mb-1" style={{ color: 'var(--theme-text)' }}>
                  {analyticsData.tokens?.total_used != null ? Number(analyticsData.tokens.total_used).toLocaleString() : '—'}
                  <span className="text-xs font-normal ml-2" style={{ color: 'var(--theme-muted)' }}>tokens recorded</span>
                </div>
                {analyticsData.tokens?.credit_balance != null && (
                  <div className="text-xs" style={{ color: 'var(--theme-muted)' }}>
